script:
function setupList({ call, columns, filters, setFilters }) {

    // Add key columns for MIS
    columns.push({
        label: "Payment Status",
        key: "custom_mis_status",
        width: "130px",
    })

    columns.push({
        label: "Entity",
        key: "custom_entity",
        width: "130px",
    })

    columns.push({
        label: "Submitted",
        key: "docstatus",
        width: "100px",
    })

    return {
        columns,
        bulkActions: [
            {
                label: "✅ Bulk Approve US Payments",
                onClick: (selectedRows) => {
                    const leadNames = selectedRows.map(r => r.name)

                    if (!leadNames.length) {
                        alert("Please select at least one lead.")
                        return
                    }

                    const confirm = window.confirm(
                        `Are you sure you want to approve payments for ${leadNames.length} lead(s)?\n\nMake sure you have verified each payment before approving.`
                    )

                    if (!confirm) return

                    call(
                        "aionion_custom.aionion_custom.controllers.crm_lead.bulk_approve_us_payments",
                        { lead_names: leadNames }
                    ).then((results) => {
                        alert(
                            `✅ Approved: ${results.approved.length}\n` +
                            `⏭️ Skipped: ${results.skipped.length}\n` +
                            `❌ Failed: ${results.failed.length}`
                        )
                        window.location.reload()
                    }).catch((e) => {
                        alert("Error: " + (e.message || "Something went wrong"))
                    })
                }
            }
        ]
    }
}
